#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <string.h>
#include <omp.h>

#include "define.c"

#include "file.c"
#include "timer.c"

// Removed #include "work.c" and #include "work_2.c" to fix missing file error

int main(int argc, char *argv []){

	int xmax;
	int workload;
	int mode;

	if(4 != argc){
		printf("ERROR: %d is the incorrect number of arguments, the number of arguments must be 3\n", argc-1);
		return 0;
	}
	else{
		xmax = atoi(argv[1]);
		if(0 > xmax){
			printf("ERROR: %d is the incorrect end of simulation interval, use numbers > 0\n", xmax);
			return 0;
		}

		workload = atoi(argv[2]);
		if(0 > workload){
			printf("ERROR: %d is the incorrect number of instances of simulation, use numbers > 0\n", workload);
			return 0;
		}

		mode = 0;
		mode = atoi(argv[3]);
		if(0 != mode && 1 != mode){
			printf("ERROR: %d is the incorrect mode, it should be omitted or equal to 0 or 1\n", mode);
			return 0;
		}
	}

	if(0 == mode){
		// Call work function defined elsewhere
		work(	xmax,
					workload);
	}
	else{
		// Call work_2 function defined elsewhere
		work_2(	xmax,
						workload);
	}

	return 0;
}

